  profile_invite: { ko: "친구 초대하기",        de: "Freunde einladen", en: "Invite friends", fr: "Inviter des amis" },
    profile_invite_title: { ko: "Roots 앱 초대",        de: "Roots Einladung", en: "Invite to Roots", fr: "Invitation à Roots" },
    profile_invite_text:  { ko: "🌱 Roots - 말씀에 뿌리내리고, 함께 자라다\n\n매일 큐티, 기도, 결단으로 나무를 키우는 크리스천 앱이에요.\n같이 시작해요! 👇\nhttps://christian-roots.com", de: "🌱 Roots - im Wort verwurzelt, gemeinsam wachsen\n\nEine christliche App, die Ihnen hilft, mit täglicher QT, Gebet und Entscheidung treu zu wachsen.\nLassen Sie uns gemeinsam anfangen! 👇\nhttps://christian-roots.com", en: "🌱 Roots - rooted in God's Word, growing together\n\nA Christian app that helps you grow faithfully through daily QT, prayer, and action.\nLet's begin together! 👇\nhttps://christian-roots.com", fr: "🌱 Roots - enraciné dans la Parole, grandir ensemble\n\nUne application chrétienne pour grandir fidèlement avec le QT, la prière et une décision quotidienne.\nCommençons ensemble ! 👇\nhttps://christian-roots.com" },
    profile_invite_copied:{ ko: "초대 문구를 복사했어요.", de: "Einladungstext wurde kopiert.", en: "Invitation text copied.", fr: "Texte d’invitation copié." },
